<!--
* @Author: zhangbo
* @Date: 2026/2/3 15:09
* @Descripttion: 自定义 下拉选择框 提示
-->
<template>
  <LTPages
      :title="'自定义下拉选择框 提示'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">自定义封装下拉选择框，选择框内容可自定义，如时间，单位数等。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div style="margin-bottom:15px;width: 300px;">
          <LTSelectTooltip
              :disabled="false"
              :content="TooltipContent"
              placeholder="请选择"
              :tooltipMethod="true"
              @deleteTooltip="deleteTooltip"
              @deleteTooltipAll="deleteTooltipAll">
            <template #main>
              <el-date-picker
                  v-model="dateTime"
                  placeholder="请选择"
                  value-format="yyyy-MM-dd HH:mm:ss"
                  @change="changedateTime"></el-date-picker>
            </template>
          </LTSelectTooltip>
        </div>
        <!--2、代码示例-->
        <div class="zhb-title">代码示例</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTTooltip1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTActionsForm2" title="javaScript"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>





      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      dateTime: '',
      TooltipContent: [],
      mainCode: `<template>
 <LTSelectTooltip
              :disabled="false"
              :content="TooltipContent"
              placeholder="请选择"
              :tooltipMethod="true"
              @deleteTooltip="deleteTooltip"
              @deleteTooltipAll="deleteTooltipAll">
            <template #main>
              <el-date-picker
                  v-model="dateTime"
                  placeholder="请选择"
                  value-format="yyyy-MM-dd HH:mm:ss"
                  @change="changedateTime"></el-date-picker>
            </template>
          </LTSelectTooltip>
</template>
`,
      jsCode: `export default {
  data() {
    return {
      dateTime: '',
      TooltipContent: [
        {label: '2025-02-01', value: '1'},
        {label: '2025-02-03', value: '2'},
        {label: '2025-01-14', value: '3'},
      ],
    }
  },
  methods: {
    // 自定义 下拉框+ 提示
    deleteTooltip(data) {
      this.TooltipContent = this.TooltipContent.filter(item => item.value != data.value);
    },
    deleteTooltipAll() {
      this.TooltipContent = [];
    },
    changedateTime() {
      this.TooltipContent.push({label: this.dateTime, value: this.dateTime});
      this.dateTime = '';
      this.isOpenSelect = false;
    }
  }
}`,
      // 配置参数
      tableData: [
        {
          text1:'disabled',
          text2:'是否可用',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'content',
          text2:'提示词',
          text3:'Array',
          text4:'---',
          text5:'---',
          text6:'{label:"提示词"，value:"1"}',
        },
        {
          text1:'placeholder',
          text2:'占位文本',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@deleteTooltip',
          text2:'删除单个提示',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@deleteTooltipAll',
          text2:'删除全部提示',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'---',
        }
      ],



    }
  },
  methods: {
    // 自定义 下拉框+ 提示
    deleteTooltip(data) {
      this.TooltipContent = this.TooltipContent.filter(item => item.value != data.value);
    },
    deleteTooltipAll() {
      this.TooltipContent = [];
    },
    changedateTime() {
      this.TooltipContent.push({label: this.dateTime, value: this.dateTime});
      this.dateTime = '';
      this.isOpenSelect = false;
    }
  },
}
</script>

